mapper.select:
SELECT COALESCE(SUM(pa.PREMIUM_AMOUNT), 0)
FROM tb_policy pa
WHERE pa.POLICY_STATUS = 'APPROVED'
  AND pa.EFFECT_DATE  >=  #{startDate}
  AND pa.EFFECT_DATE  <=  #{endDate}

SELECT COUNT(1)
FROM tb_policy pa
WHERE pa.POLICY_STATUS = 'APPROVED'
  AND pa.EFFECT_DATE  >=  #{startDate}
  AND pa.EFFECT_DATE  <=  #{endDate}

SELECT COUNT(DISTINCT pa.POLICY_NO)
FROM tb_policy pa
WHERE pa.POLICY_STATUS IN ('SUBMIT', 'PENDING')
  AND (
    pa.APPLY_TIME  >=  #{todayStart}
    OR EXISTS (
        SELECT 1
        FROM tb_policy_aprv_log log
        WHERE log.POLICY_NO = pa.POLICY_NO
          AND log.APRV_STATUS IN ('SUBMIT', 'PENDING')
          AND log.APRV_TIME  >=  #{todayStart}
    )
  )

SELECT COUNT(1)
FROM tb_claim c
WHERE c.APPLY_TIME  >=  #{dayStart}
  AND c.APPLY_TIME  <=  #{dayEnd}
